const staticData = $getWorkflowStaticData('global');
staticData.failedNumbers = [];

const body = $input.first().json.body;
const contactos = body.contactos || [];
const mensajeTemplate = (body.mensaje && body.mensaje.trim())
  ? body.mensaje.trim()
  : '👋🏻Hola! Nos contactamos desde Buenos Aires Logística. 🚚 Tenemos un envío de {empresa} para entregarte.\nQueremos avisarte que la entrega se realizará hoy entre las 16:00 y las 22:00 hs.\nEn caso de que por cuestiones operativas no llegue a completarse dentro de ese rango, la entrega pasará automáticamente al siguiente día hábil entre las 10:30 y las 22:00 hs.\nAgradecemos tu comprensión y quedamos atentos ante cualquier consulta 🙌';

return contactos.map(c => {
  let tel = String(c.telefono || '').replace(/\D/g, '');
  if (tel.length === 10) tel = '549' + tel;
  return { json: { chatId: tel + '@c.us', message: mensajeTemplate.replace(/\{empresa\}/gi, c.nombre_empresa || '') } };
});

const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');

try {
  const res = await fetch('http://ws-wwebjs:3000/client/sendMessage/default', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': '34d0e1f22e96ddc98de69f39295251001b7152b120dc3a72'
    },
    body: JSON.stringify({ chatId: item.chatId, content: item.message, contentType: 'string' })
  });
  const data = await res.json();
  if (!data.success) {
    if (!Array.isArray(staticData.failedNumbers)) staticData.failedNumbers = [];
    staticData.failedNumbers.push(item.chatId.replace('@c.us', ''));
  }
} catch (err) {
  if (!Array.isArray(staticData.failedNumbers)) staticData.failedNumbers = [];
  staticData.failedNumbers.push(item.chatId.replace('@c.us', ''));
}

return [{ json: item }];

const staticData = $getWorkflowStaticData('global');
const failed = staticData.failedNumbers || [];

if (failed.length === 0) return [];

// Obtener número propio vía wwebjs
let myChatId = '';
try {
  const res = await fetch('http://ws-wwebjs:3000/client/info/default', {
    headers: { 'x-api-key': '34d0e1f22e96ddc98de69f39295251001b7152b120dc3a72' }
  });
  const data = await res.json();
  const wid = data?.info?.wid?._serialized || data?.info?.wid?.user + '@c.us' || '';
  myChatId = wid;
} catch(e) {}

if (!myChatId) return [];

const lista = failed.map(n => '• ' + n).join('\n');
const message = '⚠️ ' + failed.length + ' número' + (failed.length !== 1 ? 's' : '') + ' sin WhatsApp:\n\n' + lista;

return [{ json: { chatId: myChatId, content: message, contentType: 'string' } }];
